+void VM_Version::VM_Features::print_numbers(outputStream &os, bool hexonly) const {
+  apply_to_all_features([&](uint64_t u, int idx) {
+    os.print(hexonly ? UINT64_FORMAT_0 : UINT64_FORMAT_X, u);
