+  static const size_t tunables_size_max = sizeof("AVX_Fast_Unaligned_Load") - 1;
+  char disable_str[MAX_CPU_FEATURES * (1/*','*/ + 1/*'-'*/ + tunables_size_max) + 1/*'\0'*/];
