+    }
+  };
+#define EXCESSIVE2(tunables, feature_active) shouldnotuse_set(PASTE_TOKENS(CPU_, tunables), STR(tunables), feature_active)
+#define EXCESSIVE(tunables) EXCESSIVE2(tunables, FEATURE_ACTIVE(tunables))
+  EXCESSIVE(AVX     );
+  EXCESSIVE(CX8     );
+  EXCESSIVE(FMA     );
+  EXCESSIVE(RTM     );
+  EXCESSIVE(AVX2    );
+  EXCESSIVE(BMI1    );
